      'plugincode' => '// проверяем нужное событие
if ($modx->event->name != \'OnFileManagerUpload\') {return;}
require_once MODX_CORE_PATH.\'model/phpthumb/phpthumb.class.php\';

//.000 - оригинал
//.000bg - не режет, добавляет поля (фон) сверху/снизу/по бокам до заданного размера (3/2)
//.000с - квадрат, режет снизу, если вертикальное изображение
$config = array(
  \'src\' => array(\'wp\' => 1200,\'hl\' => 1200,\'zc\' => 0,\'q\' => 90),
  //\'.orig\' => array(\'wp\' => 1920, \'hl\' => 1080,\'zc\' => 0,\'q\' => 100),

  \'.768\' => array(\'w\' => 768,\'zc\' => 0,\'q\' => 90),
  //\'.768bg\' => array(\'w\' => 768,\'h\' => 512,\'far\'=>\'C\', \'bg\'=>\'ffffff\',\'q\' => 90),
  //\'.768c\' => array(\'w\' => 768,\'h\' => 768,\'zc\' => \'T\',\'q\' => 90),

  /*\'.640\' => array(\'w\' => 640,\'zc\' => 0,\'q\' => 90),
  \'.640bg\' => array(\'w\' => 640,\'h\' => 426,\'far\'=>\'C\', \'bg\'=>\'ffffff\',\'q\' => 90),
  \'.640c\' => array(\'w\' => 640,\'h\' => 640,\'zc\' => \'T\',\'q\' => 90),

  \'.480\' => array(\'w\' => 480,\'zc\' => 0,\'q\' => 90),
  \'.480bg\' => array(\'w\' => 480,\'h\' => 320,\'far\'=>\'C\', \'bg\'=>\'ffffff\',\'q\' => 90),
  \'.480c\' => array(\'w\' =>480,\'h\' => 480,\'zc\' => \'T\',\'q\' => 90),*/

  \'.360\' => array(\'w\' => 360, \'h\' => 240, \'zc\' =>\'C\',\'q\' => 90),
  //\'.360bg\' => array(\'w\' => 360,\'h\' => 240,\'far\'=>\'C\', \'bg\'=>\'ffffff\',\'q\' => 90),
  \'.360c\' => array(\'w\' => 360,\'h\' => 360,\'zc\' => \'T\',\'q\' => 90),
  
  //\'.150c\' => array(\'w\' => 150,\'h\' => 150,\'zc\' => \'T\',\'q\' => 90),

);
$file = $modx->event->params[\'files\'][\'file\'];
$directory = $modx->event->params[\'directory\'];
$ms = $modx->event->params[\'source\'];
if($ms == null){return;}
$msProperties = $ms->get(\'properties\');
$directory = $msProperties[\'basePath\'][\'value\'].$directory;
$directory = str_replace(\'//\', \'/\', $directory);
if ($file[\'error\'] != 0) {return;}
$fn = $file[\'name\'];
$generator = $modx->newObject(\'modResource\');
$def_fn = pathinfo($file[\'name\'], PATHINFO_FILENAME);
$ext = pathinfo($file[\'name\'], PATHINFO_EXTENSION);
$newname=$generator->cleanAlias($file[\'name\']);
rename(MODX_BASE_PATH.$directory.$file[\'name\'], MODX_BASE_PATH.$directory.str_replace($ext, $ext, $newname));
$fn = $newname;
if(!empty($fn)){
  $fileName = MODX_BASE_PATH.$directory.$fn;
  foreach($config as $cfgKey => $cfg){
    $thumbName = \'\';
    if($cfgKey == \'src\'){
       $thumbName = MODX_BASE_PATH.$directory.$fn;
    }
    else {
       $thumbName = MODX_BASE_PATH.$directory.$cfgKey.\'/\'.$fn;
    }  
    $thumbDir = dirname($thumbName);
    if(!is_dir($thumbDir)){
        if (mkdir($thumbDir, 0777, true)) {
        }
        else { return;} 
    }
    $phpThumb = new phpThumb();
    $phpThumb->setSourceFilename($fileName);  
    foreach ($cfg as $k => $v) {
        $phpThumb->setParameter($k, $v);
    }  
    if ($phpThumb->GenerateThumbnail()) {
        if ($phpThumb->RenderToFile($thumbName)) {
          chmod($thumbName, 0666);
        }
    }
  }
}
else {return;}',
